"""
fix_menu_ux.py
Modifies create_html.py to make the dropdown menu look and behave like
a proper dropdown (with backdrop, close button, Escape key support)
instead of a sidebar.
"""

import sys
import base64

FILE = r"C:\Users\AB Digial\OneDrive\Documents\Claude\create_html.py"

# Replacement blocks stored as base64 to avoid quoting issues
OLD_CSS_B64 = ""
NEW_CSS_B64 = ""
OLD_JS_B64 = ""
NEW_JS_B64 = ""

OLD_CSS = base64.b64decode(OLD_CSS_B64).decode("utf-8")
NEW_CSS = base64.b64decode(NEW_CSS_B64).decode("utf-8")
OLD_JS = base64.b64decode(OLD_JS_B64).decode("utf-8")
NEW_JS = base64.b64decode(NEW_JS_B64).decode("utf-8")

with open(FILE, "r", encoding="utf-8") as f:
    content = f.read()

original_len = len(content)
errors = []

# Change 1 - CSS
if OLD_CSS in content:
    content = content.replace(OLD_CSS, NEW_CSS, 1)
    print("[OK] Change 1 (CSS): replacement applied.")
else:
    errors.append("Change 1 (CSS): OLD block NOT found in file.")
    print("[FAIL] " + errors[-1])

# Change 2 - JS
if OLD_JS in content:
    content = content.replace(OLD_JS, NEW_JS, 1)
    print("[OK] Change 2 (JS):  replacement applied.")
else:
    errors.append("Change 2 (JS): OLD block NOT found in file.")
    print("[FAIL] " + errors[-1])

if errors:
    print(f"\n{len(errors)} replacement(s) FAILED. File was NOT written.")
    sys.exit(1)

# Verify the new blocks are present
checks = [
    (".menu-backdrop CSS", ".menu-backdrop {{" in content),
    ("@keyframes backdropIn", "@keyframes backdropIn" in content),
    (".menu-close CSS", ".menu-close {{" in content),
    ("menu-panel a:last-child", ".menu-panel a:last-child" in content),
    ("backdrop JS creation", "backdrop.className" in content),
    ("closeBtn JS", "closeBtn.className" in content),
    ("Escape key handler", "Escape" in content),
    ("Jump to Section header", "Jump to Section" in content),
    ("Emoji-free labels", 'label: "Flexibility Guide"' in content),
]

all_ok = True
for name, ok in checks:
    status = "PASS" if ok else "FAIL"
    if not ok:
        all_ok = False
    print(f"  verify {name}: [{status}]")

if not all_ok:
    print("\nSome verifications failed. File was NOT written.")
    sys.exit(1)

with open(FILE, "w", encoding="utf-8") as f:
    f.write(content)

print(f"\nFile written successfully.")
print(f"  Original size: {original_len:,} chars")
print(f"  New size:      {len(content):,} chars")
print(f"  Delta:         {len(content) - original_len:+,} chars")
print("\nAll changes applied and verified.")
